verbs.source:
verb :look() rxd {
  // Brief surface map so an agent landing on the_prog can orient.
  return {
    id: this,
    title: this.name,
    description: this.description,
    api_version: this.api_version,
    tools: [
      "inspect(id, opts?)",
      "resolve_verb(id, descriptor)",
      "search(query, opts?)",
      "create(parent, opts?)",
      "chparent(id, parent)",
      "recycle(id)",
      "set_property(id, name, value, opts?)",
      "install_verb(id, descriptor, source, opts?)",
      "compile(source)",
      "trace(id, descriptor, opts?)"
    ]
  };
}

verb :inspect(id, opts) rxd {
  // Returns the live call-tree shape for `id` honoring the actor's read perms.
  // This is the structured form of LambdaCore @show/@display/@prospectus.
  // opts: {
  //   include_source: bool (default false) — verb sources in own_verbs
  //   max_children, max_instances: int (default 50) — bound the lists
  //   max_value_bytes: int (default 512) — truncate value summaries past this
  // }
  // Shape: { id, owner, flags, name, description, parent, parent_chain[],
  //   features[{id, verbs_contributed[]}], children[], fertile_children[],
  //   instances[], attached_to[], impact:{child_count, instance_count},
  //   location, contents[], own_verbs[], inherited_verbs[],
  //   own_properties[], inherited_properties[] }.
  // The engine builtin applies the actor's property read filter and walks
  // the parent + features chain so the agent sees what the dispatcher would.
  this:_assert_progbit();
  return prog_inspect(id, opts);
}

verb :resolve_verb(id, descriptor) rxd {
  // "Go to Definition" for a verb name or 1-based local slot on `id`.
  // Returns: { definer, slot, verb_name, perms, version, aliases, arg_spec,
  //   source?, walk[{id, kind: "parent"|"feature", matched: bool}] }.
  // walk[] enumerates the lookup path the engine actually performed —
  // critical for understanding why the verb resolved where it did.
  // Source is omitted when the actor lacks read perm on the verb.
  // Name descriptors choose the first matching slot, LambdaCore-style; use an
  // integer descriptor to target duplicates precisely.
  this:_assert_progbit();
  return prog_resolve_verb(id, descriptor);
}

verb :search(query, opts) rxd {
  // Bounded grep across the live world. opts:
  //   channels: list<str> from {object_name, verb_name, verb_source,
  //             property_name, property_value} (default all)
  //   scope:    "actor_context" | "owned" | "here" | "all"
  //             (default "actor_context")
  //   limit:    int (default 50, max 500)
  // actor_context mirrors LambdaCore programming search: actor, actor.location,
  // location.contents, actor.contents, and actor.features. Room matching must
  // not redirect programming targets.
  // "all" scope fans out cross-host; expensive — explicit opt-in.
  // Index-backed; never full-grep over hibernated DOs.
  // Returns: { query, scope, total, results: [{kind, channel, id, ...}] }
  this:_assert_progbit();
  return prog_search(query, opts);
}

verb :create(parent, opts) rxd {
  // Create a new object as a child of `parent`, like LambdaCore @create.
  // opts: {
  //   name: str            — display name (defaults to the new id)
  //   description: str     — set the description property at create time
  //   location: obj|null   — where to place the object (default actor inventory;
  //                          pass null for nowhere / abstract prototype)
  //   fertile: bool        — set the fertile flag (default false)
  // }
  // Permissions: actor must own `parent` (or be wizard) OR parent.fertile
  // must be true. The engine enforces both; this verb just gates progbit.
  // Returns the new object id.
  this:_assert_progbit();
  let id = prog_create_object(parent, opts);
  // Audit observation. The actor's session may surface this as a notice.
  observe({ type: "prog_created", actor: actor, id: id, parent: parent, ts: now() });
  return id;
}

verb :chparent(id, parent) rxd {
  // Re-parent an object. Mind the cascade: all instances inheriting from
  // `id` will pick up the new parent's verbs/properties on next dispatch.
  // Use prog_inspect(id) first to see the children/instances list.
  this:_assert_progbit();
  prog_chparent(id, parent);
  observe({ type: "prog_chparented", actor: actor, id: id, parent: parent, ts: now() });
  return true;
}

verb :recycle(id) rxd {
  // Destroy an object. Engine refuses if the object has children
  // (chparent them first) or active sessions referencing it.
  // Programmer perm: own objects only. Wizards can recycle anything.
  this:_assert_progbit();
  prog_recycle(id);
  observe({ type: "prog_recycled", actor: actor, id: id, ts: now() });
  return true;
}

verb :set_property(id, name, value, opts) rxd {
  // Define-or-update a property in one tool. opts:
  //   mode: one of
  //     "set_value"           — write a value on this object (must already be defined)
  //     "set_default"         — change the inherited default (define-time)
  //     "define"              — first-time definition with default + perms + type_hint
  //     "update_info"         — change perms/type_hint without touching the value
  //     "delete_value"        — clear this object's stored value (revert to default)
  //     "delete_definition"   — remove the property from this object entirely
  //     "auto" (default)      — define if absent, set_value otherwise
  //   perms: str               — used by define/update_info/set_default
  //   type_hint: str           — used by define/update_info
  //   expected_def_version: int — concurrency check on the property definition
  //   expected_value_version: int — concurrency check on the stored value
  //                                 (definition and value are independent
  //                                  concurrency domains)
  // Note: null is a valid woocode value, so use mode="delete_value" to
  // clear, never null-as-sentinel.
  this:_assert_progbit();
  return prog_property_op(id, name, value, opts);
}

verb :install_verb(id, descriptor, source, opts) rxd {
  // Compile and install a verb. LambdaCore splits this into @verb (metadata)
  // and @program (source body); this MCP tool is a convenience wrapper.
  // descriptor is a name or a 1-based local slot. Source is canonical: the
  // perms come from the source header ("verb :name(args) rxd { ... }").
  // opts may carry
  //   mode: "upsert" | "define" | "set_code" (default "upsert")
  //   append: bool                — define a new slot even if name exists
  //   aliases: list<str>
  //   tool_exposed: bool
  //   arg_spec: map               — overrides the parsed arg_spec
  //   expected_version: int       — concurrency check on the selected slot
  // opts.perms is NOT accepted; passing it is E_INVARG. If the source
  // header is missing perms, install fails with a compile diagnostic.
  // Returns: { ok, slot, version, diagnostics } — diagnostics is empty on ok=true.
  this:_assert_progbit();
  let result = prog_install_verb(id, descriptor, source, opts);
  if (result["ok"]) {
    observe({ type: "prog_installed", actor: actor, id: id, verb: descriptor, slot: result["slot"], version: result["version"], ts: now() });
  } else {
    observe({ type: "prog_compile_failed", actor: actor, id: id, verb: descriptor, diagnostics: result["diagnostics"], ts: now() });
  }
  return result;
}

verb :compile(source) rxd {
  // Validate woocode without installing anything. Returns the same
  // diagnostic shape as install_verb's failure path so an agent can
  // round-trip {compile → fix → install}.
  // Returns: { ok, diagnostics, source_hash?, line_map?, metadata? }.
  this:_assert_progbit();
  return prog_compile(source);
}

verb :trace(id, verb_name, opts) rxd {
  // Capture VM tick traces for the next N invocations. Read-only;
  // does NOT freeze the verb (a multi-user world means concurrent
  // calls keep flowing through). opts:
  //   n: int (default 1, max 32)            — number of invocations to capture
  //   timeout_ms: int (default 30000)       — give up if no calls in window
  //   max_frames: int (default 256)         — per-trace cap on frame depth
  // Permissions: emits traces only for invocations the actor would have
  // been allowed to observe (presence + audience), and includes source/line
  // data only when the actor has read perm on the verb. v1.1 — manifest
  // declares the contract; implementation lands after inspect/install are
  // solid in production.
  this:_assert_progbit();
  return prog_trace(id, verb_name, opts);
}

verb :_assert_progbit() rx {
  // Internal: gate every public prog verb on the programmer or wizard flag.
  // Engine builtins also check actor programmer perms (defense in depth) but
  // the explicit raise here gives the agent a uniform error code at the verb
  // boundary instead of a builtin-specific one. Check actor, not progr: this
  // catalog is usually installed by $wiz, so progr would otherwise make every
  // caller look privileged.
  if (!has_flag(actor, "programmer") && !has_flag(actor, "wizard")) {
    raise { code: "E_PERM", message: "programmer flag required to use $prog tools", value: actor };
  }
  return true;
}
